local G = DYCInfoPanel local TableContains = G.lib.TableContains local Round = function(num) return math.floor(num + 0.5) end local Clamp = function(num, min, max) return math.min(math.max(num, min), max) end local function IsNumber(o) return o ~= nil and type(o) == "number" end local function IsPosNumber(o) return IsNumber(o) and o > 0x0 end local function IsNonNegNumber(o) return IsNumber(o) and o >= 0x0 end local function IsNegNumber(o) return IsNumber(o) and o < 0x0 end local function IsNonZeroNumber(o) return IsNumber(o) and o ~= 0x0 end local function IsString(o) return o ~= nil and type(o) == "string" end local function IsTable(o) return o ~= nil and type(o) == "table" end local function IsFunction(o) return o ~= nil and type(o) == "function" end local function IsNonEmptyString(o) return IsString(o) and #o > 0x0 end local function ConcatStrings(spl, ...) local tbl = {...} if IsTable(tbl[0x1]) then tbl = tbl[0x1] end local result = "" local count = 0x0 for k, v in pairs(tbl) do if IsNonEmptyString(v) or IsNumber(v) then count = count + 0x1 result = result..(count > 0x1 and spl or "" )..v end end return result end local TableCount = function(t) local c = 0x0 for k, v in pairs(t) do c = c + 0x1 end return c end local function IsDST() return false end local function DYCGetPlayer() if IsDST() then return ThePlayer else return GetPlayer() end end local function DYCGetWorld() if IsDST() then return TheWorld else return GetWorld() end end local function GetString(key, default) return G.localization:GetString(key, default) end local function GetFormattedTime(s, short, gameunit) if gameunit then local d = s / TUNING.TOTAL_DAY_TIME d = math.floor(d * 0xa + 0.5) / 0xa return d..GetString( "timer_day" ) end local m = math.max(math.floor(s / 0x3c), 0x0) local h = math.max(math.floor(m / 0x3c), 0x0) s = s - m * 0x3c m = m - h * 0x3c s = math.floor(s) if short then return(h > 0x0 and h..GetString( "timer_hour" ) or "" )..(m > 0x0 and m..GetString( "timer_minute" ) or "" )..(s > 0x0 and s..GetString( "timer_second" ) or "" ) else return(h > 0x0 and h..GetString( "timer_hour" ) or "" )..((m > 0x0 or h > 0x0) and m..GetString( "timer_minute" ) or "" )..s..GetString( "timer_second" ) end end local function GetNumberString(value) return ""..(value >= 0x14 and Round(value) or Round(value * 0xa) / 0xa) end local function GetPercentString(value) return(value >= 0.2 and Round(value * 0x64) or Round(value * 0x3e8) / 0xa).."%" end local function GetSeasonString(s) local str = IsNonEmptyString(s) and STRINGS.UI and STRINGS.UI.SANDBOXMENU and STRINGS.UI.SANDBOXMENU[string.upper(s)] return str end local function GetNameString(prefab) local str = IsNonEmptyString(prefab) and STRINGS.NAMES[string.upper(prefab)] for i = 0x1, 0x9 do if str then break end str = str or (IsNonEmptyString(prefab) and STRINGS.NAMES[string.upper(prefab)..i]) end return str end local function BattedGetBatNumber(self) local count = 0x0 for i, interiorname in ipairs(self.batcaves) do local interiorSpawner = GetWorld().components.interiorspawner local interior = interiorSpawner and interiorSpawner:GetInteriorByName(interiorname) if interior and interior.prefabs and #interior.prefabs > 0x0 then for i = #interior.prefabs, 0x1, - 0x1 do local potentialprefab = interior.prefabs[i] if potentialprefab.name == "vampirebat" then count = count + 0x1 end end end if interior and interior.object_list and #interior.object_list > 0x0 then for i = #interior.object_list, 0x1, - 0x1 do local prefab = interior.object_list[i] if prefab.prefab == "vampirebat" then count = count + 0x1 end end end end return count end local function GetTimeToNextFullMoon(cycles, norm) local p = math.floor(cycles / 0x2) % (0x8) if p == 0x4 then return 0x0 end local nextFullMoon = 0x8 while nextFullMoon - cycles - norm <= 0x0 do nextFullMoon = nextFullMoon + 0x10 end return(nextFullMoon - cycles - norm) * TUNING.TOTAL_DAY_TIME end local function Start(watcher) if not G.cfgs.notifications then return end local colorDanger = {0x1, 0x0, 0x0} local colorWarning = {0x1, 0.5, 0x0} local colorNormal = {0x1, 0x1, 0x1} local world = DYCGetWorld() local clock = GetClock() local comps = world and world.components local hounded = comps and comps.hounded local hounded_warned1 = false local hounded_wt1 = 0x78 local hounded_warned2 = false local hounded_wt2 = 0x258 local hounded_attacked = false local batted = comps and comps.batted local batted_warned1 = false local batted_wt1 = 0x78 local batted_warned2 = false local batted_wt2 = 0x258 local batted_lt = 0xf423f local batted_ln = 0x0 local volcanomanager = comps and comps.volcanomanager local vm_warned1 = false local vm_wt1 = 0x1e local vm_warned2 = false local vm_wt2 = 0x78 local vm_warned3 = false local vm_wt3 = 0x1e0 local vm_lt = 0xf423f local vm_none = false local basehassler = comps and comps.basehassler local basehassler_warned = {} local basehassler_lt = {} local basehassler_wt1 = 0x3b local basehassler_wt2 = 0x1e0 local basehassler_wt3 = 0x2a30 local rocmanager = comps and comps.rocmanager local rocmanager_warned = {false, false, false} local rocmanager_wt = {0x78, 0x1e0, 0x2a30} local rocmanager_lt = 0xf423f local bloodMoonActived = clock.bloodmoon_active local dayCompleted = false world:ListenForEvent( "daycomplete" , function(world, data) if dayCompleted then return end dayCompleted = true world:DoTaskInTime(FRAMES, function() dayCompleted = false local numcycles = clock and clock.numcycles local norm = clock and clock:GetNormTime() local timeToFullMoon = GetTimeToNextFullMoon(numcycles, norm) if timeToFullMoon == 0x0 then G.PushBanner(GetString( "fullmoontimer2" ), 0xc, colorNormal) end end) end) local phaseChanged = false local lastPhase = "" world:ListenForEvent( "phasechange" , function(world, data) if phaseChanged then return end phaseChanged = true world:DoTaskInTime(FRAMES, function() phaseChanged = false local nightmareclock = IsTable(world.components.nightmareclock) and world.components.nightmareclock local phase = nightmareclock and nightmareclock.phase local timeleft = nightmareclock and IsFunction(nightmareclock.GetTimeLeftInEra) and nightmareclock:GetTimeLeftInEra() if IsNonEmptyString(phase) then if lastPhase ~= "warn" and phase == "warn" and IsPosNumber(timeleft) then G.PushBanner(string.format(GetString( "watcher_nightmareclock1" ), GetFormattedTime(timeleft)), 0xc, colorWarning, true) elseif lastPhase ~= "nightmare" and phase == "nightmare" then G.PushBanner(GetString( "watcher_nightmareclock2" ), 0xc, colorDanger, true) elseif lastPhase == "nightmare" and phase ~= "nightmare" then G.PushBanner(GetString( "watcher_nightmareclock3" ), 0xc, colorNormal) end lastPhase = phase end end) end) local interval = 0.5 local timer = 0x0 world:DoPeriodicTask(FRAMES, function() timer = timer + FRAMES if timer >= interval then timer = 0x0 if clock.bloodmoon_active ~= bloodMoonActived then bloodMoonActived = clock.bloodmoon_active if bloodMoonActived then G.PushBanner(GetString( "watcher_bloodmoon1" ), 0xc, colorDanger, true) else G.PushBanner(GetString( "watcher_bloodmoon2" ), 0xc, colorNormal) end end if hounded then local timetoattack = hounded.timetoattack timetoattack = IsNumber(timetoattack) and timetoattack or 0x0 local houndstorelease = hounded.houndstorelease houndstorelease = IsNumber(houndstorelease) and houndstorelease or 0x0 local shouldWarn = false if not hounded_warned1 and timetoattack <= hounded_wt1 then shouldWarn = true elseif not hounded_warned2 and timetoattack <= hounded_wt2 then shouldWarn = true end if shouldWarn then local str = GetString( "timer_warning" )..": "..string.format(GetString( "houndtimer" ), Round(houndstorelease), GetFormattedTime(timetoattack)) G.PushBanner(str, 0xc, colorWarning, true) end if not hounded_attacked and timetoattack <= 0x0 then G.PushBanner(GetString( "watcher_houndattack" ), 0xc, colorDanger, true) end if timetoattack > hounded_wt1 then hounded_warned1 = false else hounded_warned1 = true end if timetoattack > hounded_wt2 then hounded_warned2 = false else hounded_warned2 = true end if timetoattack > 0x0 then hounded_attacked = false else hounded_attacked = true end end if batted then local timetoattack = batted.timetoattack local batnum = BattedGetBatNumber(batted) batnum = IsNumber(batnum) and batnum or 0x0 local shouldWarn = false if not batted_warned1 and timetoattack <= batted_wt1 then shouldWarn = true elseif not batted_warned2 and timetoattack <= batted_wt2 then shouldWarn = true end if shouldWarn then local str = GetString( "timer_warning" )..": "..string.format(GetString( "battimer" ), Round(batnum), GetFormattedTime(timetoattack)) G.PushBanner(str, 0xc, colorWarning, true) end if batted_lt < timetoattack and batted_ln > 0x0 then G.PushBanner(GetString( "watcher_batattack" ), 0xc, colorDanger, true) end if timetoattack > batted_wt1 then batted_warned1 = false else batted_warned1 = true end if timetoattack > batted_wt2 then batted_warned2 = false else batted_warned2 = true end batted_lt = timetoattack batted_ln = batnum end if volcanomanager then local segs = IsFunction(volcanomanager.GetNumSegmentsUntilEruption) and volcanomanager:GetNumSegmentsUntilEruption() local segtime = IsNonNegNumber(TUNING.SEG_TIME) and TUNING.SEG_TIME local daytime = IsNonNegNumber(TUNING.TOTAL_DAY_TIME) and TUNING.TOTAL_DAY_TIME if IsNonNegNumber(segs) and segtime and daytime then local timeleftinseg = math.floor(daytime * GetClock():GetNormTime() / segtime) * segtime timeleftinseg = daytime * GetClock():GetNormTime() - timeleftinseg local timeleft = segs * segtime - timeleftinseg local shouldWarn = false if vm_none then shouldWarn = true elseif not vm_warned1 and timeleft <= vm_wt1 then shouldWarn = true elseif not vm_warned2 and timeleft <= vm_wt2 then shouldWarn = true elseif not vm_warned3 and timeleft <= vm_wt3 then shouldWarn = true end if shouldWarn then local str = GetString( "timer_warning" )..": "..string.format(GetString( "volcanotimer" ), GetFormattedTime(timeleft)) G.PushBanner(str, 0xc, colorWarning, true) end if vm_lt < timeleft and vm_lt <= 0x2 then G.PushBanner(GetString( "watcher_volcano" ), 0xc, colorDanger, true) end if timeleft > vm_wt1 then vm_warned1 = false else vm_warned1 = true end if timeleft > vm_wt2 then vm_warned2 = false else vm_warned2 = true end if timeleft > vm_wt3 then vm_warned3 = false else vm_warned3 = true end vm_lt = timeleft vm_none = false else vm_lt = 0xf423f vm_none = true end end if basehassler then local hasslers = basehassler.hasslers if IsTable(hasslers) and next(hasslers) then for k, hassler in pairs(hasslers) do local timer = IsTable(hassler) and hassler.timer local prefab = IsTable(hassler) and hassler.prefab local state = IsFunction(basehassler.GetHasslerState) and basehassler:GetHasslerState(k) local stateStr = IsNonEmptyString(state) and (state == "WAITING" or state == "WARNING" ) and "("..GetString( "timer_"..state)..")" or "" if not basehassler_warned[hassler] then basehassler_warned[hassler] = {[0x1] = false,[0x2] = false,[0x3] = false} end local warned = basehassler_warned[hassler] if IsNumber(timer) and IsNonEmptyString(prefab) and IsNonEmptyString(stateStr) then basehassler_lt[hassler] = timer local shouldWarn = false if not warned[0x1] and timer <= basehassler_wt1 then shouldWarn = true elseif not warned[0x2] and timer <= basehassler_wt2 then shouldWarn = true elseif not warned[0x3] and timer <= basehassler_wt3 then shouldWarn = true end if timer > basehassler_wt1 then warned[0x1] = false else warned[0x1] = true end if timer > basehassler_wt2 then warned[0x2] = false else warned[0x2] = true end if timer > basehassler_wt3 then warned[0x3] = false else warned[0x3] = true end if shouldWarn then local nameStr = GetNameString(hassler.prefab) or "" if IsNonEmptyString(nameStr) then local s = nameStr..stateStr..":"..GetFormattedTime(timer) G.PushBanner(s, 0xc, colorWarning, true) end end elseif IsTable(hassler) then if warned[0x1] or warned[0x2] or warned[0x3] then warned[0x1] = false warned[0x2] = false warned[0x3] = false local nameStr = GetNameString(hassler.prefab) or "" if IsNonEmptyString(nameStr) and IsNumber(basehassler_lt[hassler]) and basehassler_lt[hassler] <= 0x2 then G.PushBanner(string.format(GetString( "watcher_hassler" ), nameStr), 0xc, colorDanger, true) end basehassler_lt[hassler] = 0xf423f end end end end end if rocmanager then local spawntime = rocmanager.dycSpawnTime local timeleft = IsNumber(spawntime) and spawntime - GetTime() or 0x0 local disabled = rocmanager.disabled local nameStr = STRINGS.UI.CUSTOMIZATIONSCREEN.NAMES.ROC or "" if IsNonEmptyString(nameStr) and not disabled and timeleft >= 0x0 then local shouldWarn = false for i = 0x1, #rocmanager_warned do if not rocmanager_warned[i] and IsNumber(rocmanager_wt[i]) and timeleft <= rocmanager_wt[i] and timeleft >= 0x1 then shouldWarn = true break end end for i = 0x1, #rocmanager_warned do if IsNumber(rocmanager_wt[i]) and timeleft > rocmanager_wt[i] then rocmanager_warned[i] = false else rocmanager_warned[i] = true end end if shouldWarn then local s = nameStr..":"..GetFormattedTime(timeleft) G.PushBanner(s, 0xc, colorNormal) end if timeleft < interval and timeleft ~= rocmanager_lt and rocmanager_lt <= 0x2 then G.PushBanner(string.format(GetString( "watcher_hassler" ), nameStr), 0xc, colorNormal) end rocmanager_lt = timeleft else rocmanager_lt = 0xf423f end end end end) end local Watcher = {} function Watcher:Start() Start(self) end return Watcher 